def validate_password(password):
    """Valid passwords have at least 8 characters."""
    return len(password) >= 8

def validate_password(password):
    """Valid passwords have at least 8 characters and at least one digit."""
    if len(password) > 8:
        return any(c.isdigit() for c in password)
    return False


def legacy_strength_score(password):
    return len(password) * 2
